const TK=$env.TRELLO_KEY,TT=$env.TRELLO_TOKEN,BOARD=$env.TRELLO_BOARD_ID;
const L={todo:$env.TRELLO_LIST_TODO,prog:$env.TRELLO_LIST_INPROGRESS,wait:$env.TRELLO_LIST_WAITING,review:$env.TRELLO_LIST_INREVIEW,owner:$env.TRELLO_LIST_OWNER};
const GHTOKEN=$env.GITHUB_TOKEN,OWNER_CHAT=$env.OWNER_CHAT,BALE=$env.BALE_BOT_TOKEN;
const CLAUDE_BRIDGE='http://host.docker.internal:8787/v1/messages';
const req=(o)=>this.helpers.httpRequest(o);
const tUrl=(p)=>'https://api.trello.com/1/'+p+(p.includes('?')?'&':'?')+'key='+TK+'&token='+TT;
const tGet=async(p)=>{try{return await req({method:'GET',url:tUrl(p),json:true});}catch(e){return [];}};
const tPost=async(p)=>req({method:'POST',url:tUrl(p),json:true});
const tPut=async(p)=>req({method:'PUT',url:tUrl(p),json:true});
const tDel=async(p)=>{try{return await req({method:'DELETE',url:tUrl(p),json:true});}catch(e){return null;}};
const bale=async(chat,text)=>{try{await req({method:'POST',url:'https://tapi.bale.ai/bot'+BALE+'/sendMessage',body:JSON.stringify({chat_id:chat,text}),headers:{'content-type':'application/json'},json:false});}catch(e){}};
const claude=async(prompt,mt)=>{const r=await req({method:'POST',url:CLAUDE_BRIDGE,body:JSON.stringify({model:'claude-opus-4-8',max_tokens:mt||3000,messages:[{role:'user',content:prompt}]}),headers:{'content-type':'application/json'},json:false});const j=typeof r==='string'?JSON.parse(r):r;return (j.content&&j.content[0]&&j.content[0].text)||'';};
const strip=(s)=>String(s||'').replace(/```json|```/g,'').trim();
const jparse=(t)=>{let s=strip(t);try{return JSON.parse(s);}catch(e){}let a=s.indexOf('{'),b=s.lastIndexOf('}');if(a>=0&&b>a){try{return JSON.parse(s.slice(a,b+1));}catch(e){}}let c=s.indexOf('['),d=s.lastIndexOf(']');if(c>=0&&d>c){try{return JSON.parse(s.slice(c,d+1));}catch(e){}}return null;};
const enc=(s)=>Buffer.from(s||'','utf8').toString('base64');
const normRepo=(u)=>String(u||'').trim().replace(/\.git$/,'').replace(/^https?:\/\/github\.com\//i,'').replace(/^github\.com\//i,'');
const gh=async(method,path,body,raw)=>{const r=await req({method,url:'https://api.github.com'+path,headers:{Authorization:'Bearer '+GHTOKEN,Accept:raw?'application/vnd.github.raw+json':'application/vnd.github+json','User-Agent':'n8n-bot'},body:body?JSON.stringify(body):undefined,json:false});if(raw)return typeof r==='string'?r:JSON.stringify(r);try{return typeof r==='string'?JSON.parse(r):r;}catch(e){return r;}};
const meta=(d)=>{d=String(d||'');const g=(re)=>{const m=d.match(re);return m?m[1].trim():'';};return{repo:normRepo(g(/repo:\s*(\S+)/)),project:g(/project:\s*(.+)/),ref:g(/ref:\s*(\S+)/)};};
const trackOf=(name)=>{const m=String(name||'').match(/^\[(backend|frontend|mobile)\]/);return m?m[1]:'backend';};
const CI_YML="name: CI\non:\n  pull_request:\n    branches: [ develop ]\njobs:\n  backend:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-python@v5\n        with: { python-version: '3.12' }\n      - name: backend tests\n        run: |\n          if [ -d backend ]; then\n            cd backend\n            pip install -r requirements.txt 2>/dev/null || pip install django djangorestframework pytest pytest-django\n            python -m pytest -q\n          else echo \"no backend yet\"; fi\n  frontend:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-node@v4\n        with: { node-version: '20' }\n      - name: frontend tests\n        run: |\n          if [ -f frontend/package.json ]; then\n            cd frontend\n            npm ci || npm install\n            npm test -- --watch=false --browsers=ChromeHeadless\n          else echo \"no frontend yet\"; fi\n  mobile:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-java@v4\n        with: { distribution: 'temurin', java-version: '17' }\n      - name: mobile tests\n        run: |\n          if [ -f mobile/gradlew ]; then\n            cd mobile\n            chmod +x gradlew && ./gradlew test\n          else echo \"no mobile yet\"; fi\n";

// helperهای Trello: کامنت، لیبل قرمز، و برگرداندن کارت به To Do با ثبت دلیل
const ensureRedLabel=async()=>{ try{ const labels=await tGet('boards/'+BOARD+'/labels'); let lab=(labels||[]).find(l=>l.color==='red'&&l.name==='باگ'); if(!lab){ lab=await tPost('boards/'+BOARD+'/labels?name='+encodeURIComponent('باگ')+'&color=red'); } return lab&&lab.id; }catch(e){ return null; } };
const addRedLabel=async(id)=>{ try{ const lid=await ensureRedLabel(); if(lid) await tPost('cards/'+id+'/idLabels?value='+lid); }catch(e){} };
const removeRedLabel=async(id)=>{ try{ const lid=await ensureRedLabel(); if(lid){ try{await tDel('cards/'+id+'/idLabels/'+lid);}catch(e){} } }catch(e){} };
const commentCard=async(id,text)=>{ try{ await tPost('cards/'+id+'/actions/comments?text='+encodeURIComponent(text)); }catch(e){} };
const back=async(id,reason)=>{ await commentCard(id,'🔴 '+reason); await addRedLabel(id); await tPut('cards/'+id+'?idList='+L.todo); };
const readRole=async(role)=>{ try{ const s=await req({method:'GET',url:'http://host.docker.internal:8787/role/'+role,json:false}); return String(s||'').trim(); }catch(e){ return ''; } };
const cards=await tGet('lists/'+L.review+'/cards?fields=name,desc');
const sd=$getWorkflowStaticData('global'); sd.tl_diag=sd.tl_diag||{};
const diag=async(key,msg)=>{ if(sd.tl_diag[key])return; sd.tl_diag[key]=Date.now(); await bale(OWNER_CHAT,'🩺 '+msg); };
const tlRole=(await readRole('tech-lead'))||'تو Tech Lead هستی.';
const out=[];
if(!cards.length){ return [{json:{idle:1,note:'In Review خالی است'}}]; }
for(const c of cards){ const mm=meta(c.desc); if(!mm.repo){ await diag(c.id+':norepo','کارت «'+c.name+'» در In Review فوتر «repo:» در توضیحش ندارد؛ Tech Lead نمی‌داند روی کدام ریپو کار کند و رد می‌شود.'); continue; } const [o,r]=mm.repo.split('/'); const cardId=c.id; const track=trackOf(c.name);
  let prNum=null; try{ const list=await gh('GET','/repos/'+o+'/'+r+'/pulls?state=open&base=develop&per_page=100'); const match=(list||[]).find(p=>p&&p.head&&p.head.ref==='task/'+cardId); if(match)prNum=match.number; }catch(e){ await diag(c.id+':listerr','خطا در گرفتن لیست PRها برای «'+c.name+'» ('+mm.repo+'): '+e.message+' — توکن گیت‌هاب/نام ریپو را بررسی کن.'); continue; }
  if(!prNum){ await diag(c.id+':nopr','برای «'+c.name+'» هیچ PR بازی به develop با شاخه‌ی task/'+cardId+' پیدا نشد. شاید PR بسته/merge شده یا شاخه‌اش فرق دارد.'); continue; }
  let pr; try{ pr=await gh('GET','/repos/'+o+'/'+r+'/pulls/'+prNum); }catch(e){ await diag(c.id+':prget','خواندن PR #'+prNum+' برای «'+c.name+'» ناموفق: '+e.message); continue; }
  // کانفلیکت
  if(pr.mergeable===false || pr.mergeable_state==='dirty'){
    await bale(OWNER_CHAT,'⚠️ کانفلیکت در PR #'+prNum+' ('+c.name+'). بسته شد و کارت برای بازسازی روی develop برگشت.');
    try{await gh('POST','/repos/'+o+'/'+r+'/issues/'+prNum+'/comments',{body:'کانفلیکت با develop؛ بسته می‌شود و دوباره ساخته خواهد شد.'});}catch(e){}
    try{await gh('PATCH','/repos/'+o+'/'+r+'/pulls/'+prNum,{state:'closed'});}catch(e){}
    await back(cardId,'کانفلیکت با develop در PR #'+prNum+'؛ PR بسته شد و تسک برای بازسازی برگشت.'); out.push({json:{conflict:prNum}}); continue;
  }
  // وضعیت CI — هیچ‌وقت بدون تأیید CI (build + test سبز) ریویو/merge نکن
  let runs=[]; try{ runs=((await gh('GET','/repos/'+o+'/'+r+'/commits/'+pr.head.sha+'/check-runs')).check_runs)||[]; }catch(e){}
  const ageMin=(Date.now()-new Date(pr.created_at).getTime())/60000;
  if(!runs.length){
    await diag(c.id+':noci:'+pr.head.sha,'CI روی PR #'+prNum+' («'+c.name+'») هیچ check-run ندارد. مطمئن شو روی ریپو GitHub Actions فعال است و فایل .github/workflows/ci.yml وجود دارد و روی pull_request به develop تریگر می‌خورد. تا تأیید CI، ریویو/merge انجام نمی‌شود.');
    out.push({json:{noCI:prNum,ageMin:Math.round(ageMin)}}); continue;
  }
  if(runs.some(x=>x.status!=='completed')){ await diag(c.id+':waitci:'+pr.head.sha,'CI برای «'+c.name+'» (PR #'+prNum+') در حال اجراست؛ منتظر اتمام.'); out.push({json:{waitCI:prNum}}); continue; }
  const failed=runs.filter(x=>x.conclusion&&!['success','neutral','skipped'].includes(x.conclusion));
  if(failed.length){
    // لاگ خطا را از output و annotationهای هر چک رد‌شده جمع کن و در کارت بگذار
    let log='';
    for(const x of failed){ log+='### '+x.name+' → '+x.conclusion+'\n'; if(x.output&&x.output.summary) log+=String(x.output.summary).slice(0,800)+'\n'; try{ const anns=await gh('GET','/repos/'+o+'/'+r+'/check-runs/'+x.id+'/annotations'); for(const a of (anns||[]).slice(0,12)){ log+='- '+(a.path||'')+(a.start_line?(':'+a.start_line):'')+' — '+(a.message||a.title||'')+'\n'; } }catch(e){} }
    log=log.trim().slice(0,5000)||'بدون جزئیات';
    await bale(OWNER_CHAT,'❌ CI برای «'+c.name+'» رد شد (build/test). لاگ خطا در کارت Trello ثبت شد.');
    try{await gh('POST','/repos/'+o+'/'+r+'/issues/'+prNum+'/comments',{body:'CI رد شد؛ کارت برای فیکس برگشت.'});}catch(e){}
    try{await gh('PATCH','/repos/'+o+'/'+r+'/pulls/'+prNum,{state:'closed'});}catch(e){}
    await back(cardId,'CI رد شد (build/test) در PR #'+prNum+'. لاگ خطا:\n'+log); out.push({json:{ciFail:prNum}}); continue;
  }
  // ریویو کد
  let files=[]; try{ files=await gh('GET','/repos/'+o+'/'+r+'/pulls/'+prNum+'/files'); }catch(e){}
  const diff=files.map(f=>'FILE: '+f.filename+'\n'+(f.patch||'')).join('\n\n').slice(0,12000);
  const rev=jparse(await claude(tlRole+'\n\nاین diff را در برابر تسک و استاندارد استک ('+track+') بسنج. خروجی فقط JSON با کلیدهای verdict (مقدار APPROVE یا REQUEST_CHANGES) و comment (فارسی). فقط JSON. تسک: '+c.name+'\n'+c.desc+'\n\nDIFF:\n'+diff,1800))||{verdict:'REQUEST_CHANGES',comment:'خروجی ریویو خوانده نشد'};
  if(rev.verdict==='APPROVE'){
    try{await gh('POST','/repos/'+o+'/'+r+'/pulls/'+prNum+'/reviews',{event:'APPROVE',body:rev.comment});}catch(e){}
    await removeRedLabel(cardId);
    // merge خودکار در develop (squash)؛ در صورت شکست، fallback به merge دستی
    let merged=false,mergeErr='';
    try{ const mr=await gh('PUT','/repos/'+o+'/'+r+'/pulls/'+prNum+'/merge',{merge_method:'squash',commit_title:c.name+' (#'+prNum+')'}); merged=!!(mr&&mr.merged); if(!merged)mergeErr=(mr&&mr.message)||'merge ناموفق'; }catch(e){ mergeErr=e.message; }
    if(merged){
      try{await gh('DELETE','/repos/'+o+'/'+r+'/git/refs/heads/task/'+cardId);}catch(e){}
      await tPut('cards/'+cardId+'?idList='+L.owner);
      await bale(OWNER_CHAT,'✅ merge شد در develop: '+c.name+'\nPR: '+pr.html_url);
      out.push({json:{merged:prNum}});
    } else {
      await tPut('cards/'+cardId+'?idList='+L.owner);
      await bale(OWNER_CHAT,'✅ تأیید شد ولی merge خودکار نشد ('+mergeErr+'). دستی merge کن: '+pr.html_url);
      out.push({json:{approved:prNum,mergeFail:mergeErr}});
    }
  } else {
    try{await gh('POST','/repos/'+o+'/'+r+'/pulls/'+prNum+'/reviews',{event:'REQUEST_CHANGES',body:rev.comment});}catch(e){}
    try{await gh('PATCH','/repos/'+o+'/'+r+'/pulls/'+prNum,{state:'closed'});}catch(e){}
    await back(cardId,'Tech Lead نیاز به اصلاح اعلام کرد: '+(rev.comment||''));
    await bale(OWNER_CHAT,'🔧 نیاز به اصلاح: '+c.name+'\n'+(rev.comment||''));
    out.push({json:{changes:prNum}});
  }
}
return out.length?out:[{json:{idle:1}}];
